struct BankAccount {
    var balance: Double

    mutating func deposit(amount: Double) {
        balance += amount
        print("Deposited \(amount). New Balance is \(balance)")
    }
}

var myAccount = BankAccount(balance: 100.0)
myAccount.deposit(amount: 50.0)
